"use strict";(globalThis.webpackChunkggv_blogs=globalThis.webpackChunkggv_blogs||[]).push([[511],{5982(e,n,r){r.r(n),r.d(n,{assets:()=>s,contentTitle:()=>l,default:()=>k,frontMatter:()=>d,gallery1Images:()=>b,gallery2Images:()=>g,metadata:()=>a,toc:()=>h});const a=JSON.parse('{"id":"GijsGroteVleesverbouwing/bbq","title":"Barbecue","description":"In Gijs Grote Vleesverbouwing gebruikt Gijs voornamelijk zijn Barbecue om geweldige gerechten te bereiden.","source":"@site/i18n/nl/docusaurus-plugin-content-docs/current/3_GijsGroteVleesverbouwing/1_bbq.mdx","sourceDirName":"3_GijsGroteVleesverbouwing","slug":"/GijsGroteVleesverbouwing/bbq","permalink":"/GijsGroteVleesverbouwing/bbq","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":2,"frontMatter":{"sidebar_position":2},"sidebar":"GijsGroteVleesverbouwing","previous":{"title":"Intro","permalink":"/GijsGroteVleesverbouwing/"},"next":{"title":"Pulled pork","permalink":"/GijsGroteVleesverbouwing/pulledPork"}}');var i=r(4848),t=r(8453),o=r(5643);const d={sidebar_position:2},l="Barbecue",s={},b=[{original:"/img/ggvv/bbq/IMG_20201003_121733-scaled.jpg",thumbnail:"/img/ggvv/bbq/IMG_20201003_121733-scaled.jpg"},{original:"/img/ggvv/bbq/IMG_20201003_121743-scaled.jpg",thumbnail:"/img/ggvv/bbq/IMG_20201003_121743-scaled.jpg"}],g=[{original:"/img/ggvv/bbq/IMG_20201105_142326-scaled.jpg",thumbnail:"/img/ggvv/bbq/IMG_20201105_142326-scaled.jpg"},{original:"/img/ggvv/bbq/IMG_20201105_142337-scaled.jpg",thumbnail:"/img/ggvv/bbq/IMG_20201105_142337-scaled.jpg"},{original:"/img/ggvv/bbq/IMG_20201105_142710-scaled.jpg",thumbnail:"/img/ggvv/bbq/IMG_20201105_142710-scaled.jpg"},{original:"/img/ggvv/bbq/IMG_20201105_142345-scaled.jpg",thumbnail:"/img/ggvv/bbq/IMG_20201105_142345-scaled.jpg"},{original:"/img/ggvv/bbq/IMG_20201105_144706-scaled.jpg",thumbnail:"/img/ggvv/bbq/IMG_20201105_144706-scaled.jpg"},{original:"/img/ggvv/bbq/IMG_20201105_144825_1-scaled.jpg",thumbnail:"/img/ggvv/bbq/IMG_20201105_144825_1-scaled.jpg"},{original:"/img/ggvv/bbq/IMG_20201105_144814-scaled.jpg",thumbnail:"/img/ggvv/bbq/IMG_20201105_144814-scaled.jpg"}],h=[{value:"Snake methode",id:"snake-methode",level:2},{value:"Minion methode",id:"minion-methode",level:2}];function u(e){const n={h1:"h1",h2:"h2",header:"header",p:"p",...(0,t.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(n.header,{children:(0,i.jsx)(n.h1,{id:"barbecue",children:"Barbecue"})}),"\n","\n","\n",(0,i.jsx)(n.p,{children:"In Gijs Grote Vleesverbouwing gebruikt Gijs voornamelijk zijn Barbecue om geweldige gerechten te bereiden.\nEen goede barbecue is leuk om te hebben, maar niet iedereen heeft 600 tot 1200 euro over voor een barbecue en dit hoeft ook helemaal niet!\nNatuurlijk zal een dure barbecue het werk gemakkelijker maken, dus als u veel barbecuet en het geld er voor over heeft raad Gijs het zeker aan.\nMaar in Gijs Grote Vleesverbouwing probeert Gijs u te laten zien hoe u ook op een simpele barbecue prachtige gerechten kunt bereiden.\nHet belangrijkste is, dat uw barbecue een deksel heeft."}),"\n",(0,i.jsx)(n.h1,{id:"kolen-of-briketten",children:"Kolen of briketten?"}),"\n",(0,i.jsx)(n.p,{children:"Gijs is van mening dat een echte barbecue met kolen of briketten werkt, gas en elektrische barbecues komen er bij hem niet in. Bij het gebruik van een kolen barbecue rijst echter altijd de vraag: \u201cGebruik ik kolen of briketten?\u201d."}),"\n",(0,i.jsx)(n.p,{children:"Beide brandstoffen hebben dezelfde oorsprong. Houtskool is deels verbrand hout wat stabieler brand dan normaal hout. Door de zuurstof naar het vuur af te knijpen tijdens het verbranden van hout, verbranden alleen de vluchtige en daardoor minder voorspelbare elementen in het hout. Wat overblijft zijn stukken verdroogde kool die erg stabiel branden. Briketten bestaan uit vermalen en samengeperst houtskool, hetzelfde materiaal dus maar dan veel compacter.\nhebben hun voor en nadelen, Houtskool brand iets warmer dan briketten, maar is ook sneller opgebrand. Briketten branden daarin tegen wat minder warm maar wel stabiel."}),"\n",(0,i.jsx)(n.p,{children:"Iedereen heeft zijn eigen voorkeuren, en Gijs gaat niet doen of het een beter is dan het ander. Gijs prefereert zelf het gebruik van briketten voor het low-and-slow barbecue\xebn, omdat deze langer doorbranden. Het verschil in temperatuur is minimaal doordat bij deze methode altijd een deksel op de barbecue zit. Voor direct grillen gebruikt hij vaker houtskool omdat dit net wat sneller werkt."}),"\n",(0,i.jsx)("img",{src:"/img/ggvv/bbq/IMG_20201025_095244-scaled.jpg",alt:"coal",loading:"lazy",width:"100%"}),"\n",(0,i.jsx)(n.h1,{id:"de-barbecue-aanmaken",children:"De barbecue aanmaken"}),"\n",(0,i.jsx)(n.p,{children:"Gijs heeft een redelijk grote barbecue die soms wat lastiger onder controle te houden is, daarom is het voor hem extra belangrijk een goede methode te gebruiken om zijn barbecue aan te maken.\nSimpelweg een start koker vullen met briketten, aansteken en op de barbecue gooien resulteert in een veel te hoge initi\xeble temperatuur die vervolgens snel zal dalen.\nHet vlees zal hierdoor van buiten aanbranden en van binnen rauw blijven."}),"\n",(0,i.jsx)(n.h2,{id:"snake-methode",children:"Snake methode"}),"\n",(0,i.jsxs)(n.p,{children:["Om zijn barbecue voor een lange periode onder controle te houden maakt Gijs gebruik van de ",(0,i.jsx)("a",{href:"https://bbqware.be/tips-en-technieken/minion-snake-houtskool-techniek.php",children:"snake methode"})," voor het plaatsen van de briketten."]}),"\n",(0,i.jsx)(n.p,{children:"Door een soort langwerpige piramide van briketten te maken, en deze alleen aan de uiteinden aan te steken zal het vuur langzaam het spoor van briketten volgen, zo wordt de barbecue niet te warm en hoeft Gijs nagenoeg geen briketten toe te voegen.\nIndien u een kleinere barbecue heeft is het verstandiger zijn om de \u2018snake\u2019 aan slechts een kant aan te steken, anders riskeert u een te hoge temperatuur in uw barbecue."}),"\n",(0,i.jsxs)(n.p,{children:["Door de snake breder te maken, door meer lagen kolen toe te voegen, kan Gijs de barbecue warmer stoken.\nDit alles betekend overigens niet dat u uw startkoker weg moet gooien. Deze is erg handig om een kleine hoeveelheid kolen aan te maken die u vervolgens tegen het begin van de snake aanlegt (zie ",(0,i.jsx)("a",{href:"https://youtu.be/Dw3hn8aXPxc",children:"deze"})," video).\nBij het gebruik van een snake kan het namelijk 1 tot 2 uur duren voor er genoeg kolen branden om de gewenste temperatuur te bereiken, door te beginnen met een aantal hete kolen kunt u de starttijd aanzienlijk verkorten."]}),"\n",(0,i.jsx)(o.A,{items:b,loading:"lazy"}),"\n",(0,i.jsx)(n.h2,{id:"minion-methode",children:"Minion methode"}),"\n",(0,i.jsxs)(n.p,{children:["De ",(0,i.jsx)("a",{href:"https://www.youtube.com/watch?v=c7cURxn-I7w",children:"minion methode"})," is een andere veelgebruikte methode om een barbecue langer warm te houden.\nDeze methode werkt doorgaans minder lang dan de bovenstaande snake methode, maar is wel handig om hogere temperaturen te bereiken voor bijvoorbeeld het bakken van brood."]}),"\n",(0,i.jsx)(n.p,{children:"Het aanleggen van de minion methode lijkt veel op dat van de snake methode, alleen legt Gijs de snake nu helemaal rond, zodat deze geen begin of eind heeft.\nVoor de minion methode hoeft u overigens niet zo netjes te zijn als bij de snake methode.\nHierna maakt Gijs een aantal kolen aan in een startkoker, en wanneer deze kolen branden gooit hij ze in het midden van de ring. Hierdoor steken de middelste kolen de buiten liggende kolen vanzelf aan."}),"\n",(0,i.jsx)(n.p,{children:"Het verschil met de snake methode hierbij is dat er veel meer kolen gelijktijdig branden, en de barbecue dus veel heter zal worden. Hierdoor zijn de kolen echter ook eerder opgebrand, en moeten deze dus sneller bijgevuld worden."}),"\n",(0,i.jsx)(o.A,{items:g,loading:"lazy"}),"\n",(0,i.jsx)(n.h1,{id:"hout-of-kokos",children:"Hout of kokos"}),"\n",(0,i.jsxs)(n.p,{children:["Er gaan erg veel ",(0,i.jsx)("a",{href:"https://braadmaarraak.nl/kokosbriketten-overzicht/#:~:text=Ook%20bereiken%20kokosbriketten%20eenvoudig%20een,dan%20met%20n%C3%B3g%20meer%20voordelen",children:"positieve verhalen"})," rond over het gebruik van kokos briketten in plaats van houtskool.\nGijs heeft hier op het moment van schrijven nog geen ervaring mee maar is bereid dit te proberen.\nZodra hij meer ervaring heeft opgedaan met het gebruik van kokos briketten vind u hier een uitgebreide review."]})]})}function k(e={}){const{wrapper:n}={...(0,t.R)(),...e.components};return n?(0,i.jsx)(n,{...e,children:(0,i.jsx)(u,{...e})}):u(e)}}}]);